        return FfiMlsFacade(unsafeFromHandle: handle)
    }

    public static func lower(_ value: FfiMlsFacade) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiMlsFacade {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: FfiMlsFacade, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


